    },
    "MobileNet_v3_int8": {
        "path": "/home/nick/work/AutoIREE_plus_AI/AutoIREE_zoo/models/MobileNet_v3_int8/MobileNet-v3-Large-Quantized",
        "dispatches": ["module_main_dispatch_81", "module_main_dispatch_92"]
    },
    "ResNet-50_int8": {
        "path": "/home/nick/work/AutoIREE_plus_AI/AutoIREE_zoo/models/ResNet-50_int8/ResNet50Quantized",
        "dispatches": ["module_main_dispatch_87"]
    },
    "DeepLab_int8": {
        "path": "/home/nick/work/AutoIREE_plus_AI/AutoIREE_zoo/models/DeepLab_int8/deeplab-edgetpu-argmax-m",
        "dispatches": ["module_main_dispatch_103", "module_main_dispatch_104"]
    }
}

for model_name, model_info in models_to_analyze.items():
    record_base = os.path.join(model_info["path"], "record")
    if not os.path.exists(record_base):
        continue

    record_dirs = [os.path.join(record_base, d) for d in os.listdir(record_base)]
    record_dir = record_dirs[0] if record_dirs else None
    if not record_dir:
        continue

    history_file = os.path.join(record_dir, "history.log")
    benchmarks_dir = os.path.join(model_info["path"], "benchmarks")

    if not os.path.exists(history_file):
        continue

    print(f"\n{'='*160}")
    print(f"MODEL: {model_name}")
    print(f"{'='*160}")

    for dispatch_id in model_info["dispatches"]:
        # Read tile config
        tile_config_file = os.path.join(benchmarks_dir, f"{dispatch_id}_static_tile_config.json")
        if not os.path.exists(tile_config_file):
            continue

        with open(tile_config_file) as f:
            tile_config = json.load(f)

        # Get matmul operation info
        matmul_ops = {k: v for k, v in tile_config.items() if "matmul" in k}
        if not matmul_ops:
            continue

        op_name = list(matmul_ops.keys())[0]
        op_info = matmul_ops[op_name]

        print(f"\nDispatch: {dispatch_id} | Op: {op_name}")
        print(f"  Iteration Space: {op_info.get('iteration_space')}")
        print(f"  Default Tile: {op_info.get('default')}")
        print(f"  Parallel dims: {op_info.get('Parallel dimensions')}")
        print(f"  Reduction dims: {op_info.get('Reduction dimensions')}")

        # Parse history to find best matmul configs
        best_cycle = float('inf')
        best_config_json = None
        count = 0

        with open(history_file) as f:
            for line in f:
                if count > 10000:  # Limit iterations
                    break
                try:
                    entry = json.loads(line)
                    if entry["input"][2] == dispatch_id:
                        result = entry["result"]
                        cycles = result[0]
                        error = result[1]

                        if error == 0 and isinstance(cycles, (int, float)) and cycles < float('inf'):
                            if cycles < best_cycle:
                                best_cycle = cycles
                                best_config_json = entry
                            count += 1
                except:
                    pass

        if best_config_json:
            print(f"\n  Best config found (cycles: {best_cycle}):")
            configs = best_config_json["config"]["configs"]
            for i, (op_idx, tile_level, tile_type, tile_values) in enumerate(configs):
                if best_config_json["config"]["ops"][op_idx][0] == op_name:
                    print(f"    Tile level {tile_level}: {tile_values}")

PYEOF
